const r=document.getElementById("menu-toggle"),o=document.getElementById("main-nav");r?.addEventListener("click",()=>o?.classList.toggle("active"));o?.querySelectorAll("a").forEach(t=>t.addEventListener("click",()=>o.classList.remove("active")));document.querySelectorAll('nav a[href^="#"]').forEach(t=>{t.addEventListener("click",e=>{e.preventDefault();const c=document.querySelector(t.getAttribute("href"));if(c){const n=document.querySelector("header").offsetHeight;window.scrollTo({top:c.getBoundingClientRect().top+window.pageYOffset-n,behavior:"smooth"})}})});const i=document.querySelectorAll("section[id]"),a=document.querySelectorAll("nav a");window.addEventListener("scroll",()=>{let t="";i.forEach(e=>{window.pageYOffset>=e.offsetTop-120&&(t="#"+e.id)}),a.forEach(e=>{e.classList.remove("active"),e.getAttribute("href")===t&&e.classList.add("active")})});
